class Solution:
    def findLatestTime(self, s: str) -> str:
        # Replace hour part
        if s[0] == '?':
            if s[1] == '?':
                s = '11' + s[2:]
            else:
                s = '1' + s[1] + s[2:]
        elif s[1] == '?':
            if s[0] == '0':
                s = '09' + s[2:]
            else:
                s = s[0] + '1' + s[2:]

        # Replace minute part
        if s[3] == '?':
            s = s[:3] + '5' + s[4]
        if s[4] == '?':
            s = s[:4] + '9'

        return s
